--
-- TOC entry 3593 (class 2618 OID 36347)
-- Name: vista_peptido_completo _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.vista_peptido_completo AS
 SELECT p.id,
    p.secuencia,
    p.nombre_principal,
    array_agg(na.nombre) AS nombres_alternativos,
    p.longitud,
    p.peso_molecular,
    p.carga_neta,
    p.hidrofobicidad,
    p.es_natural,
    p.estado_verificacion,
    p.uniprot_id,
    p.dramp_id,
    fo.nombre_cientifico AS organismo_fuente
   FROM ((public."pÉptido" p
     LEFT JOIN public.nombre_alternativo na ON ((p.id = na.peptido_id)))
     LEFT JOIN public.fuente_organismo fo ON ((p.organismo_fuente_id = fo.id)))
  WHERE (p.activo = true)
  GROUP BY p.id, fo.nombre_cientifico;


--
-- TOC entry 3594 (class 2618 OID 36352)
-- Name: vista_actividad_peptido _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.vista_actividad_peptido AS
 SELECT p.id,
    p.nombre_principal,
    jsonb_agg(DISTINCT jsonb_build_object('organismo', ob.nombre_cientifico, 'mic_valor', po.mic_valor, 'mic_unidad', po.mic_unidad)) AS organismos,
    ( SELECT jsonb_agg(DISTINCT av.nombre_virus) AS jsonb_agg
           FROM (public.peptido_antiviral pv
             JOIN public.actividad_antiviral av ON ((pv.antiviral_id = av.id)))
          WHERE (pv.peptido_id = p.id)) AS virus,
    ( SELECT jsonb_agg(DISTINCT af.nombre_hongo) AS jsonb_agg
           FROM (public.peptido_antifungico pf
             JOIN public.actividad_antifungica af ON ((pf.antifungico_id = af.id)))
          WHERE (pf.peptido_id = p.id)) AS hongos
   FROM ((public."pÉptido" p
     LEFT JOIN public.peptido_organismo po ON ((p.id = po.peptido_id)))
     LEFT JOIN public.organismo_blanco ob ON ((po.organismo_id = ob.id)))
  WHERE (p.activo = true)
  GROUP BY p.id;


